import os
import sys
import shutil
import subprocess
import tempfile
import zipfile
from pathlib import Path

ROOT = Path(__file__).resolve().parent


def run(cmd, cwd=None, env=None):
    print("+", " ".join(cmd), flush=True)
    subprocess.run(cmd, cwd=str(cwd) if cwd else None, env=env, check=True)


def ensure_venv(venv_dir: Path):
    py = sys.executable
    if not (venv_dir / ("Scripts" if os.name == "nt" else "bin") / ("python.exe" if os.name == "nt" else "python")).exists():
        run([py, "-m", "venv", str(venv_dir)])


def venv_bin(venv_dir: Path, exe: str) -> str:
    if os.name == "nt":
        p = venv_dir / "Scripts" / (exe + (".exe" if not exe.endswith(".exe") else ""))
    else:
        p = venv_dir / "bin" / exe
    return str(p)


def install_deps(venv_dir: Path, requirements: Path):
    pip = venv_bin(venv_dir, "pip")
    run([pip, "install", "--upgrade", "pip", "setuptools", "wheel"])
    run([pip, "install", "-r", str(requirements)])


def run_tests(venv_dir: Path):
    py = venv_bin(venv_dir, "python")
    pytest = venv_bin(venv_dir, "pytest")
    if Path(pytest).exists():
        run([pytest, "-q"])
        return
    run([py, "-m", "pytest", "-q"])


def should_exclude(rel: str) -> bool:
    rel = rel.replace("\\", "/")
    if rel.startswith(".git/") or rel == ".git":
        return True
    if rel.startswith(".venv/") or rel == ".venv":
        return True
    if rel.startswith("__pycache__/") or "/__pycache__/" in rel:
        return True
    if rel.endswith(".pyc") or rel.endswith(".pyo"):
        return True
    if rel.startswith(".pytest_cache/") or "/.pytest_cache/" in rel:
        return True
    if rel.startswith(".mypy_cache/") or "/.mypy_cache/" in rel:
        return True
    if rel.startswith(".ruff_cache/") or "/.ruff_cache/" in rel:
        return True
    if rel.startswith(".tox/") or rel == ".tox":
        return True
    if rel.startswith("dist/") or rel == "dist":
        return True
    if rel.startswith("build/") or rel == "build":
        return True
    return False


def package_source(out_dir: Path, name: str = "deploy_package.zip") -> Path:
    out_dir.mkdir(parents=True, exist_ok=True)
    out_path = out_dir / name
    if out_path.exists():
        out_path.unlink()

    with zipfile.ZipFile(out_path, "w", compression=zipfile.ZIP_DEFLATED) as z:
        for p in ROOT.rglob("*"):
            if p.is_dir():
                continue
            rel = str(p.relative_to(ROOT))
            if should_exclude(rel):
                continue
            z.write(p, arcname=rel)
    return out_path


def main():
    requirements = ROOT / "requirements.txt"
    if not requirements.exists():
        print("requirements.txt not found", file=sys.stderr)
        sys.exit(2)

    venv_dir = Path(os.environ.get("VENV_DIR", str(ROOT / ".venv"))).resolve()
    out_dir = Path(os.environ.get("ARTIFACT_DIR", str(ROOT / "dist"))).resolve()
    artifact_name = os.environ.get("ARTIFACT_NAME", "deploy_package.zip")

    ensure_venv(venv_dir)
    install_deps(venv_dir, requirements)
    run_tests(venv_dir)
    artifact = package_source(out_dir, artifact_name)

    print(f"ARTIFACT={artifact}", flush=True)


if __name__ == "__main__":
    main()